#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long sum=0; int firstOdd=-1, lastOdd=-1;
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            sum+=x;
            if(x%2){
                if(firstOdd==-1) firstOdd=i;
                lastOdd=i;
            }
        }
        if(sum%2==0){
            printf("%d\n",N);
        }else{
            if(firstOdd==-1){ // should not happen
                printf("0\n");
            }else{
                int dropLeft = firstOdd+1;
                int dropRight = N-lastOdd;
                int ans = N - (dropLeft<dropRight?dropLeft:dropRight);
                printf("%d\n",ans);
            }
        }
    }
    return 0;
}

