#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        sum_val = 0
        first_odd = -1
        last_odd = -1
        for i in range(N):
            x = int(next(it))
            sum_val += x
            if x & 1:
                if first_odd == -1:
                    first_odd = i
                last_odd = i
        if sum_val % 2 == 0:
            out.append(str(N))
        else:
            drop_left = first_odd + 1
            drop_right = N - last_odd
            ans = N - min(drop_left, drop_right)
            out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

